import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  signInWithEmailAndPassword,
  createUserWithEmailAndPassword,
  sendPasswordResetEmail
} from 'firebase/auth';
import { auth } from './firebaseConfig';

const LoginForm = () => {
  const navigate = useNavigate();
  const [formType, setFormType] = useState('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  // Lista de administradores
  const adminEmails = ['edirosky@gmail.com', 'sai.cosmar@gmail.com'];

  const handleAuthAction = async (e) => {
    e.preventDefault();
    setError('');

    try {
      if (formType === 'login') {
        const userCredential = await signInWithEmailAndPassword(auth, email, password);
        const userEmail = userCredential.user.email?.toLowerCase() || '';
        
        adminEmails.includes(userEmail) ? navigate('/admin') : navigate('/app');
        
      } else if (formType === 'register') {
        await createUserWithEmailAndPassword(auth, email, password);
        alert('Cadastro realizado com sucesso!');
        setFormType('login');
        
      } else if (formType === 'reset') {
        await sendPasswordResetEmail(auth, email);
        alert('Email de recuperação enviado!');
        setFormType('login');
      }
    } catch (error) {
      handleAuthError(error);
    }
  };

  const handleAuthError = (error) => {
    console.error('Erro de autenticação:', error);
    
    const errorMessages = {
      'auth/invalid-email': 'Email inválido',
      'auth/user-disabled': 'Conta desativada',
      'auth/user-not-found': 'Usuário não encontrado',
      'auth/wrong-password': 'Senha incorreta',
      'auth/email-already-in-use': 'Email já cadastrado',
      'auth/weak-password': 'Senha deve ter pelo menos 6 caracteres',
      'auth/too-many-requests': 'Muitas tentativas. Tente mais tarde'
    };

    setError(errorMessages[error.code] || 'Erro desconhecido. Tente novamente.');
  };

  return (
    <div className="auth-container">
      <div className="auth-toggle">
        <button 
          onClick={() => setFormType('login')}
          className={formType === 'login' ? 'active' : ''}
        >
          Login
        </button>
        <button 
          onClick={() => setFormType('register')}
          className={formType === 'register' ? 'active' : ''}
        >
          Cadastro
        </button>
        <button 
          onClick={() => setFormType('reset')}
          className={formType === 'reset' ? 'active' : ''}
        >
          Resetar Senha
        </button>
      </div>

      <h2 className="auth-title">
        {{
          login: 'Acesso ao Sistema',
          register: 'Novo Cadastro',
          reset: 'Recuperação de Senha'
        }[formType]}
      </h2>

      {error && <div className="error-message">{error}</div>}

      <form onSubmit={handleAuthAction} className="auth-form">
        <div className="form-group">
          <label>Email:</label>
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value.trim())}
            required
            placeholder="seu@email.com"
          />
        </div>

        {formType !== 'reset' && (
          <div className="form-group">
            <label>Senha:</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              minLength={6}
              placeholder="••••••••"
            />
          </div>
        )}

        <button type="submit" className="auth-submit">
          {{
            login: 'Entrar',
            register: 'Cadastrar',
            reset: 'Enviar Link'
          }[formType]}
        </button>
      </form>
    </div>
  );
};

export default LoginForm; // Exportação corrigida para LoginForm